var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"정말 감사해요. 아무런 관계도 없으신데 저희 마을을 위해 나서 주시다니…….","JPN":"本当にありがとうございます。無関係な方なのにうちの村のために……","ENG":"Thank you very much. You stood up for us even when you didn’t have to...","TWN":"真的很謝謝你，明明不干你的事，竟然願意爲我們的村子挺身而出………"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런 말씀 마십시오, 모네 어머님. 모네 양에게는 일전에 크게 도움 받았으니까요.","JPN":"そんなに感謝されるようなことではありません。モネには以前かなり助けてもらいましてね。","ENG":"Don’t say that. Mone has helped us a great deal in the past.","TWN":"伯母，別那麼說。不久前我受到莫妮很大的幫助呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"서로 도우며 사는 거 아니겠습니까. 하. 하. 하.","JPN":"お互い助け合わねば。ア・ハ・ハ・ハ。","ENG":"We have to help each other, right? Ha, ha, ha.","TWN":"最美的風景不就是人嗎，哈，哈，哈。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어쩜, 믿음직스러우셔라.","JPN":"あらあ、なんて頼もしい方かしら。","ENG":"Oh my, you really are a man of virtue.","TWN":"真是個值得信賴的人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"저희 애가 사고는 안 치고 다닐까 걱정이 많았는데, 도시에서 참 좋은 분들을 만났네요.","JPN":"うちの子が都会で迷惑かけたらどうしようと心配していましたが、とてもいい方々に出会えたんですね。","ENG":"I was always worried about my girl, but I see she met very good people in the city.","TWN":"我本來很擔心我們家孩子會不會闖禍，沒想到在城市裡遇到好人呢！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그런데 모네 넌 애가 겁도 없이 총 든 사람한테 달려들기나 하고…….","JPN":"でもモネ、銃を持っている人に立ち向かうなんて……","ENG":"And Mone, what were you thinking, running to fight armed men?","TWN":"不過莫妮，你這孩子竟然衝到那群手裡拿著槍的人面前………"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"자, 잘못했슴다…….","JPN":"ご、ごめんなさい……","ENG":"I-I’m sorry...","TWN":"對不起…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어머나, 내 정신 좀 봐. 수다 떨다 식사도 못 드시게 했네요.","JPN":"あらら、私としたことが。おしゃべりに夢中になってお食事のことをうっかりしていましたわ。","ENG":"Oh, where are my manners. You must be hungry.","TWN":"哎呀，你看看我，只顧著聊天，害你們都沒辦法好好吃飯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"남편이 먼 바다로 나가서 차릴 건 부족하지만 정성껏 챙겨 봤어요. 많이 드세요.","JPN":"主人が沖まで出て釣ってきたものです。お粗末様ですが、ぜひ召し上がってください。","ENG":"My husband is out at sea and we don’t have much right now, but I did my best with what I have. Please help yourselves.","TWN":"因為莫妮的爸爸出海去了，家裡沒什麼東西，一點家常菜，你們不要客氣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우와, 엄청 맛있다! 이거 생선회 맞아요?","JPN":"うわぁー美味しい！　これ本当に刺身ですか？","ENG":"Wow, this is great! Are you sure this is raw fish?","TWN":"哇，真的很好吃！這是生魚片吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L20_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"후훗. 네. 오래 재워 둘 겨를이 없었는데 입맛에 맞으시다니 다행이네요.","JPN":"フフッ。下処理する時間がなくて心配したのですが、お口に合ってよかったですわ。","ENG":"*Smile* Yes. I didn’t have the time to marinate it fully, but I’m glad you like it.","TWN":"呵呵，對啊。沒什麼時間準備，幸好合你的胃口。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이 바닷가재도 살이 무척 부드럽군요. 사진 한 번 찍은 대가치고는 호사스럽네요.","JPN":"このエビも身がぷりぷりでとても柔らかいです。たった一枚の写真のお礼と言うには、贅沢すぎますね。","ENG":"This lobster is so creamy. What a treat we get, just for taking a simple selfie.","TWN":"這龍蝦肉也好Q彈。作爲拍一張照的代價，未免太奢侈。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"혹시 이 신선한 해산물들이…… 저 윤기가 흐르는 피부의 비결인가?","JPN":"もしかしてこの新鮮な海産物に……あの艶やかな肌の秘訣が？","ENG":"All this fresh seafood... Perhaps this is the key to her silky soft skin?","TWN":"難道這些新鮮的海鮮……就皮膚Q彈的秘訣嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠흠! 크흠!","JPN":"コホンコホン！　コホン！","ENG":"Ahem! Ahem!","TWN":"咳嗯嗯！咳嗯！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어머님, 방금 전에 마을로 들이닥쳤던 자들은 어떻게 된 겁니까?","JPN":"お母さん、さっき村を襲ってきた連中は何者ですか？","ENG":"Ma’am, who were those people who attacked your village?","TWN":"伯母，剛闖進村子的那些人到底是怎麼回事？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"아, 실은…….","JPN":"あ、実は……","ENG":"Oh, them...","TWN":"是這樣的…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"얼마 전부터 근처에 있는 리조트가 저희 마을을 없애겠다고 나섰어요.","JPN":"先日から村の近くにあるリゾートがこの村を取り壊すと言ってきたのです。","ENG":"They were sent from a nearby resort, determined to get rid of our village.","TWN":"不久前開始，附近的度假村就表示要剷平我們的村子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"투숙하는 손님들에게서 경관을 해친다는 불만이 접수됐다면서요.","JPN":"宿泊客から景観の邪魔になるという苦情が寄せられたそうです。","ENG":"It looks like their guests are filing complaints against our village, saying the place is ruining the view.","TWN":"因為住宿的客人抱怨說會破壞附近的景觀。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"경관을 해쳐요? 이렇게 예쁜 마을이요?","JPN":"景観の邪魔？　こんなにキレイな村が？","ENG":"Ruining the view? But this place is beautiful!","TWN":"這個漂亮的村子會破壞景觀？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그러게요. 리조트에 묵는 분들 눈에는 낡고 허름하게만 보였나 봐요.","JPN":"そうなんです。リゾートに泊まる方の目には古臭く見えたのかもしれませんね。","ENG":"I know. But the guests in the resort think this place is just a bunch of old shacks.","TWN":"可不是嗎？可能住在度假村的人覺得我們的村子很破爛吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"저희들이 떠나지 않으니까, 저렇게 용병들까지 끌어들일 만큼요.","JPN":"私たちを追い出すために、あんな凶暴な傭兵を雇うほどです。","ENG":"We didn’t give in, and now they are sending mercenaries.","TWN":"因為我們不離開，所以就找傭兵來鬧事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"언론이나 인터넷에는 안 알리셨어요?","JPN":"マスコミやインターネットには知らせてないんですか？","ENG":"How about making it public, like tipping off a reporter, or posting it on the internet?","TWN":"你沒有PO上爆料公社嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"수소문해서 방송사에 연락해 봤지만 그 때뿐이었어요.","JPN":"色々調べてマスコミにも連絡してみたのですが、その時だけでした。","ENG":"We tried, but it didn’t work well.","TWN":"我有嘗試聯絡過電視台，但都沒有下文。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"요즘엔 저희 같은 사람들이 아니라도 침식 현상 때문에 고향을 잃고 고생하는 분들이 많으니까요.","JPN":"このご時世ですから、この村だけではなく侵食現象で故郷を失って苦労している人々はたくさんいますからね。","ENG":"There are so many others suffering far worse than us thanks to the Counterside Effect, and problems like ours aren’t a big deal.","TWN":"最近有很多因為侵蝕現象而失去故鄉的辛苦人，當然就見怪不怪囉。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음, 그거 참…….","JPN":"ふむ、それはなんとも言えませんね。","ENG":"Well, I don’t know what to say...","TWN":"嗯嗯，那真是… "},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"게다가 무서운 침식체들이 나타난다는 소문까지 퍼져서……","JPN":"それに、怖い侵食体が現れているという噂まで広まって……","ENG":"And now with the rumor of Corrupted Objects appearing nearby...","TWN":"再加上傳聞村裡有可怕的侵蝕體出現………"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"지금 보시는 것처럼 여름철인데도 마을이 한산할 지경이에요.","JPN":"ご覧のとおり、夏のピークシーズンなのに閑散としているんです。","ENG":"No one is coming to our village, even though it’s the peak of summer.","TWN":"所以就像現在你們看到的這樣，雖然是夏天，但村子還是冷冷清清的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"침식체라면 혹시 그 펭귄들이요?","JPN":"侵食体というのはあのペンギンたちのことですか？","ENG":"C.O.s... You mean the penguins?","TWN":"侵蝕體是指那些企鵝嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"아, 맞아요. 저희 마을에서는 모네 동생들이라고 부르고 있어요.","JPN":"ええ、そうなんです。この村ではモネの妹と呼んでいますわ。","ENG":"Oh, yes. We call them Mone’s little sisters.","TWN":"是的。在我們村子裡，大家都說他們是莫妮的妹妹呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"언제부터인가 나타나서는 마을 어르신들이랑 놀아 드리다가 사라지더라고요.","JPN":"いつからか急に現れては、村のお年寄りたちのお相手をして消えていくんです。","ENG":"They just come out of nowhere, hang around the village elders, and leave...","TWN":"不知從什麼時候開始，他們會突然出現和村裡的長輩們玩耍，然後就又消失不見。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"침식체라는 건 보통 사람들한테 해를 끼치지 않나요?","JPN":"侵食体というのは普通、人に害を与えるものなんですよね？","ENG":"But C.O.s usually attack people, don’t they?","TWN":"侵蝕體一般不會傷害人嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"어쩌면 리조트 측이 소문을 퍼뜨렸을지도 모르죠.","JPN":"もしかしたらリゾート側がわざと広めた噂かもしれません。","ENG":"Maybe it was the resort that spread that rumor.","TWN":"很可能是度假村那邊散佈的謠言。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"관광객들이 많으면 방금처럼 우격다짐으로 사람들을 쫓아내려 하기도 어려울 테니까요.","JPN":"観光客が多いと、さっきのように言いがかりで村人を追い出そうとすることも難しいですからね。","ENG":"Having too many tourists in your village might make it difficult for them to get rid of this place.","TWN":"畢竟遊客多的話，就不好用剛才那樣強硬的手段逼迫人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"세상에…….","JPN":"そんな……","ENG":"Oh my...","TWN":"天啊…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"우으…….","JPN":"むう……！","ENG":"Argh...","TWN":"唔…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주, 주인님! 엄니를 도와 주십셔! 주인님은 메이드장님도 도와 주시지 않으셨슴까!","JPN":"ご、ご主人様！　村を助けてくださいっす！　ご主人様はメイド長も助けてくれたっすよね？","ENG":"M-Master, please help my mama! You helped the Chief Maid too, right, sir?","TWN":"拜託主人幫幫我媽媽吧！您不是也幫助過女僕長嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"얘, 얘가 갑자기 왜 그러니? 쉬러 오신 분들한테 그럼 못 써!","JPN":"モ、モネ！？　休むためにいらした方にいけないわよ！","ENG":"M-Mone, don’t say that to our guests! They are only here to enjoy their vacation!","TWN":"這孩子是怎麼搞的？人家是來休息的，怎麼可以這樣為難人家呢！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아닙니다, 어머님. 말씀드렸던 대로 서로 도우며 사는 거죠.","JPN":"いいえ、お母さん。先ほども言いましたが、助け合いは大事だと思います。","ENG":"No, ma’am. Like I said, we have to help each other out.","TWN":"別這麼說，伯母。就像我剛才說的，最美的風景是人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"게다가 위기는 기회가 될 수 있는 법. 제게 방법이 있습니다.","JPN":"それに、この危機をチャンスにかえる方法を私は知っています。","ENG":"Also, a crisis can be turned into an opportunity. I have an idea.","TWN":"而且危機就是轉機，我有好方法。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"정말이심까, 주인님?!","JPN":"ホントっすか、ご主人様！？","ENG":"Really, Master?!","TWN":"真的嗎，主人？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님, 잠시 이쪽으로.","JPN":"社長、しばしこちらへ。","ENG":"Boss, can we talk for a second?","TWN":"老闆，借一步說話。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응? 왜 그러나?","JPN":"うむ？　どうしたんだい？","ENG":"Hm? What is it?","TWN":"嗯？什麼事？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"여기서 저희가 끼어들면 괜히 상황만 복잡해질지도 모릅니다.","JPN":"ここで私たちが介入してしまうと、状況が余計複雑になるかもしれません。","ENG":"It might make things complicated if we get involved.","TWN":"我們插手的話，情況可能會變得複雜。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"게다가 이번 일은 해결한다고 해서 저희에게 득이 될 것도 없습니다. 참으시죠.","JPN":"しかも今回のことは解決したとしても、私たちが得するようなこともありません。だからここは我慢しましょう。","ENG":"Plus, meddling in this affair won’t get us anything. Please reconsider.","TWN":"而且解決這件事對我們也沒有好處，就忍著吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 모네 양이 저렇게 부탁하지 않나.","JPN":"しかし、モネがあんなにお願いしているじゃないか。","ENG":"Oh, come on, Mone is asking for our help.","TWN":"可是莫妮那樣拜託我。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"제가 평소에 드리는 부탁도 좀 그렇게 너그러운 마음으로 고려해 주시면 안 됩니까?","JPN":"私が普段申し上げているお願い事も、そんな優しい気持ちで考慮してくださると助かりますが。","ENG":"But you never take on my requests with such a generous manner.","TWN":"那我平常拜託你時，你也可以像這樣認真考慮嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠, 하지만 머신 갑 화보집은 아무리 자네 부탁이래도 포기하기가 좀……","JPN":"コホン、しかしマシーン甲写真集はいくら君のお願いとはいえ諦めるにはちょっと……","ENG":"Ahem, I just couldn’t give up my Machine G.A.P. Photo Book...","TWN":"咳咳，如果是機械·我超帥寫真集，不管你再怎麼拜託我，我也無法放棄…"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님께서 모네 양 부탁을 거절하기 어려우시다면 제가 하도록 하겠습니다.","JPN":"社長からモネに断りづらいなら、私から言います。","ENG":"If you can’t say no, I’ll say it for you.","TWN":"如果老闆不想當壞人，那就由我來扮黑臉吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"얘기하는 동안 자리만 잠시 비워 주시죠. 제가 신속하게…….","JPN":"話し合う間だけしばらく席を外してください。","ENG":"You can go outside. I’ll just wrap it up real quick and—","TWN":"我跟莫妮談的時候，你就先迴避一下，我會快狠準地……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"아, 아직 얘기 중이셨네요. 죄송해요.","JPN":"あ、まだお話の途中でしたね、すみません。","ENG":"Oh, you’re still talking. I’m sorry.","TWN":"哎呀，你們還在談嗎？抱歉。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아닙니다, 어머님. 그런데 무슨 일로?","JPN":"いいえ、お母さん。どうしましたか？","ENG":"It’s alright, ma’am. What is it?","TWN":"沒關係，找我有什麼事嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"실은, 피부로 고민하시는 것 같아서 저희 집안에 전해 내려오는 코코넛 크림을 좀 꺼내 왔는데…….","JPN":"実は、お肌の悩みがあるようでしたので我が家秘伝のココナッツオイルを少し持ってきたのですが……","ENG":"I heard you mentioning something about skin, so I brought you some coconut cream. This is my family’s special recipe.","TWN":"是這樣的，我覺得你好像爲皮膚所苦，這是我們家祖傳的椰子霜………"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"역시 괜히 부담만 드리는 것 같네요. 도시 분들한테 이런 건 거추장스럽기만 하겠죠?","JPN":"いえ、やっぱりこんな物を渡されても困りますよね。都会の方だから、もっといい化粧品をお待ちのはずですし……","ENG":"But I guess you don’t really need it, do you? You’re from a big city, and this must be nothing but a hassle for you...","TWN":"這樣會不會讓你有壓力？都市人應該不喜歡這樣吧？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……사장님의 계획에 대해 자세히 들어 봐야겠군요.","JPN":"……社長の計画について詳しく聞かせてもらいましょう。","ENG":"... Boss, you said you had an idea. Let me hear it.","TWN":"…老闆的具體計畫是什麼？說來聽聽。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네, 너무 속 보이지 않나.","JPN":"君、下心が丸見えだぞ。","ENG":"Aren’t you being a bit too thin?","TWN":"你會不會變太快？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"기브 앤 테이크입니다. 경영인의 기본 원리죠.","JPN":"ギブ&テイクです。経営者の基本原理でしょう。","ENG":"I say it’s a tit for tat. The basic principle of business.","TWN":"禮尚往來，是公司經營的基本原則。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그래서, 어떻게 할 생각이십니까?","JPN":"それで、何をするつもりですか？","ENG":"So, what are we going to do?","TWN":"所以，接下來要怎麼做？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPEAR_MAID_NULL_Q","text":{"KOREA":"뭐야, 이게. 저기는 온갖 요리 다 먹는데 우린 코코넛 주스가 고작이네.","JPN":"なによ、これ。あっちは色んな料理が食べ放題なのに私たちはココナッツジュースしかないじゃない。","ENG":"What is this? They are having a feast, and all we get is coconut juice.","TWN":"這是怎樣，他們在那邊大魚大肉，我們卻只有椰子汁？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_Q","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_Q","text":{"KOREA":"감시 중에는 이것도 사치입니다. 정보부 출신이니 잘 알고 있을 텐데요.","JPN":"監視中にはこれも贅沢です。情報部出身ですしよく知ってるはずだと思いますが。","ENG":"Be thankful for this, since we’re on a surveillance mission. You’re with intel, you should know.","TWN":"監視中還有椰子汁喝，你要感恩。你不是情報部出身的嗎？應該很習慣吧？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_Q","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_Q","text":{"KOREA":"읍?!","JPN":"うっ！？","ENG":"Oof!","TWN":"唔？！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_Q","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SPEAR_MAID_NULL_Q","text":{"KOREA":"왜, 왜 그래? 갑자기?","JPN":"ど、どうしたの？　急に？","ENG":"W-what? What’s wrong?","TWN":"怎麼了嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_Q","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_Q","text":{"KOREA":"……이 코코넛, 한 모금만 마셨는데 혀가 쓰라려요.","JPN":"……このココナッツジュース、一口飲んだだけで舌がヒリヒリします。","ENG":"... I just had a sip, and for some reason, my tongue stings.","TWN":"… 這個椰子汁我喝了一口，舌頭好辣喔。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_Q","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_Q","text":{"KOREA":"아, 좀 밍밍하길래 가져 왔던 칠리 소스로 간 좀 맞췄어.","JPN":"ああ、ちょっと味が薄い気がして、チリソースでパンチを効かせてみたの。","ENG":"Oh, it was too bland, so I put some chili sauce in.","TWN":"哦～我覺得味道有點淡，就用辣椒醬調了一下味道。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_MAID_NULL_Q","text":{"KOREA":"딱히 고마워하지 않아도 돼.","JPN":"お礼はいいわ。","ENG":"You don’t have to thank me.","TWN":"不用客氣。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_NULL_Q","text":{"KOREA":"아얏!","JPN":"痛っ！","ENG":"Ow!","TWN":"哎唷！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_Q","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SNAP"}]`);export{e as default};